const input = $input.first().json;

// Handle different webhook data structures:
// 1. rawBody enabled: body is a JSON string
// 2. rawBody disabled: body is an object or data is at root level
let body;
if (typeof input.body === 'string') {
  body = JSON.parse(input.body);
} else if (input.body && typeof input.body === 'object') {
  body = input.body;
} else {
  body = input;
}

return {
  json: {
    sessionId: body.sessionId,
    taskId: body.taskId,
    chatId: body.chatId,
    messageId: body.messageId,
    selectedModel: body.selectedModel || 'veo3_fast',
    modelType: body.modelType || 'veo',
    statusEndpoint: body.statusEndpoint || '/api/v1/veo/record-info',
    attempt: body.attempt || 1,
    isExtend: body.isExtend || false,
    parentSessionId: body.parentSessionId || null
  }
};

const inputData = $('Parse Input').first().json;
const statusResponse = $input.first().json;
const modelType = inputData.modelType || 'veo';

let isCompleted = false;
let isFailed = false;
let videoUrl = null;
let status = 'processing';

if (modelType === 'veo') {
  // Veo response: successFlag 0=Generating, 1=Success, 2=Failed, 3=Generation Failed
  const successFlag = statusResponse.data?.successFlag;
  isCompleted = successFlag === 1;
  isFailed = successFlag === 2 || successFlag === 3;
  // For 9:16 aspect ratio, use originUrls; otherwise use resultUrls
  const resultUrls = statusResponse.data?.response?.resultUrls || [];
  const originUrls = statusResponse.data?.response?.originUrls || [];
  videoUrl = originUrls[0] || resultUrls[0] || null;
} else if (modelType === 'market') {
  // Market API response format (Sora2, Seedance)
  // State can be: 'pending', 'processing', 'success', 'failed'
  const taskState = statusResponse.data?.state || statusResponse.data?.status;
  isCompleted = taskState === 'success' || taskState === 'completed' || taskState === 'COMPLETED';
  isFailed = taskState === 'failed' || taskState === 'FAILED' || taskState === 'error';

  // Try multiple locations for video URL
  // 1. Direct fields
  videoUrl = statusResponse.data?.videoUrl || statusResponse.data?.output?.video || statusResponse.data?.result?.video_url;

  // 2. Parse resultJson if it exists
  if (!videoUrl && statusResponse.data?.resultJson) {
    try {
      const resultJson = JSON.parse(statusResponse.data.resultJson);
      videoUrl = resultJson.resultUrls?.[0] || resultJson.videoUrl || resultJson.video_url || resultJson.url;
    } catch (e) {
      // resultJson parsing failed, continue with null
    }
  }

  // 3. Check response object
  if (!videoUrl && statusResponse.data?.response) {
    const response = typeof statusResponse.data.response === 'string' 
      ? JSON.parse(statusResponse.data.response) 
      : statusResponse.data.response;
    videoUrl = response.resultUrls?.[0] || response.videoUrl || response.video_url;
  }
}

if (isCompleted) status = 'completed';
if (isFailed) status = 'failed';

return {
  json: {
    ...inputData,
    status,
    isCompleted,
    isFailed,
    videoUrl,
    rawResponse: statusResponse
  }
};

// videoUrl already available from Parse Status via record-info endpoint
const inputData = $('Parse Status').first().json;
const parseInputData = $('Parse Input').first().json;

return {
  json: {
    ...inputData,
    isExtend: parseInputData.isExtend || false,
    parentSessionId: parseInputData.parentSessionId || null
  }
};

// Get data from Merge After Concat (via Skip Concat or Concatenate path)
const mergeData = $('Merge After Concat').first().json;
const redisResult = $input.first().json;

// Redis returns data in propertyName field
const redisValue = redisResult.propertyName || redisResult;
const session = typeof redisValue === 'string' ? JSON.parse(redisValue) : redisValue;

const s3Url = `https://your-s3-endpoint.com/shorts/videos/${session.sessionId}.mp4`;

// Get video URL from merge data (passed through Skip Concat or Concat path)
let videoUrl = mergeData.videoUrl;

// Fallback: try to get from rawResponse
if (!videoUrl && mergeData.rawResponse) {
  const raw = mergeData.rawResponse;
  videoUrl = raw.data?.response?.originUrls?.[0] || raw.data?.response?.resultUrls?.[0];
}

// Fallback 2: try Get Final URL directly
if (!videoUrl) {
  try {
    const finalUrlData = $('Get Final URL').first().json;
    videoUrl = finalUrlData.videoUrl;
    if (!videoUrl && finalUrlData.rawResponse) {
      videoUrl = finalUrlData.rawResponse.data?.response?.originUrls?.[0] || finalUrlData.rawResponse.data?.response?.resultUrls?.[0];
    }
  } catch (e) {
    // Get Final URL not accessible
  }
}

// Store video URL and raw response for publishing
return {
  json: {
    ...session,
    videoUrl: videoUrl,
    rawResponse: mergeData.rawResponse,
    s3Url: s3Url,
    status: 'video_ready',
    updatedAt: new Date().toISOString()
  }
};

