const session = $input.first().json;

const metadata = `Video Metadata
==============
Session ID: ${session.sessionId}
Generated: ${session.createdAt || 'N/A'}
Completed: ${new Date().toISOString()}

Original Input
--------------
Text: ${session.originalInput?.text || 'N/A'}
Photo: ${session.originalInput?.photoUrl ? 'Yes' : 'No'}

Video Generation
----------------
Model: ${session.selectedModel || 'veo3'}
Model Name: ${session.modelName || 'Veo 3.1'}
Task ID: ${session.taskId || 'N/A'}
Template: ${session.template || 'general'}
Balance at Generation: ${session.balanceAtGeneration || 'N/A'} credits

YouTube Metadata
----------------
Title: ${session.youtubeMetadata?.title || 'N/A'}
Description: ${session.youtubeMetadata?.description || 'N/A'}
Tags: ${session.youtubeMetadata?.tags?.join(', ') || 'N/A'}

Generated Prompt
----------------
${session.generatedPrompt || 'N/A'}

URLs
----
S3: ${session.s3Url || 'N/A'}
KIE: ${session.videoUrl || 'N/A'}`;

// Convert text to binary for S3 upload
const binaryData = Buffer.from(metadata, 'utf-8');

return {
  json: {
    ...session,
    metadataKey: `videos/${session.sessionId}_metadata.txt`
  },
  binary: {
    metadata: {
      data: binaryData.toString('base64'),
      mimeType: 'text/plain',
      fileName: `${session.sessionId}_metadata.txt`
    }
  }
};

// Pass through for non-extend videos
const inputData = $('Get Final URL').first().json;
return {
  json: {
    sessionId: inputData.sessionId,
    isExtend: false,
    videoUrl: inputData.videoUrl,
    rawResponse: inputData.rawResponse
  }
};
